  1348→// Caches list of services in the registry, and creates a map
  1349→// of hostname to service
  1350→func (ps *PushContext) initServiceRegistry(env *Environment) error {
  1351→	// Sort the services in order of creation.
  1352→	allServices := SortServicesByCreationTime(env.Services())
  1353→	for _, s := range allServices {
  1354→		svcKey := s.Key()
  1355→		// Precache instances
  1356→		for _, port := range s.Ports {
  1357→			if _, ok := ps.ServiceIndex.instancesByPort[svcKey]; !ok {
  1358→				ps.ServiceIndex.instancesByPort[svcKey] = make(map[int][]*ServiceInstance)
  1359→			}
  1360→			instances := make([]*ServiceInstance, 0)
  1361→			instances = append(instances, env.InstancesByPort(s, port.Port, nil)...)
  1362→			ps.ServiceIndex.instancesByPort[svcKey][port.Port] = instances
  1363→		}
  1364→
  1365→		if _, f := ps.ServiceIndex.HostnameAndNamespace[s.Hostname]; !f {
  1366→			ps.ServiceIndex.HostnameAndNamespace[s.Hostname] = map[string]*Service{}
  1367→		}
  1368→		ps.ServiceIndex.HostnameAndNamespace[s.Hostname][s.Attributes.Namespace] = s
  1369→
  1370→		ns := s.Attributes.Namespace
  1371→		if len(s.Attributes.ExportTo) == 0 {
  1372→			if ps.exportToDefaults.service[visibility.Private] {
  1373→				ps.ServiceIndex.privateByNamespace[ns] = append(ps.ServiceIndex.privateByNamespace[ns], s)
  1374→			} else if ps.exportToDefaults.service[visibility.Public] {
  1375→				ps.ServiceIndex.public = append(ps.ServiceIndex.public, s)
  1376→			}
  1377→		} else {
  1378→			// if service has exportTo ~ - i.e. not visible to anyone, ignore all exportTos
  1379→			// if service has exportTo *, make public and ignore all other exportTos
  1380→			// if service has exportTo ., replace with current namespace
  1381→			if s.Attributes.ExportTo[visibility.Public] {
  1382→				ps.ServiceIndex.public = append(ps.ServiceIndex.public, s)
  1383→				continue
  1384→			} else if s.Attributes.ExportTo[visibility.None] {
  1385→				continue
  1386→			} else {
  1387→				// . or other namespaces
  1388→				for exportTo := range s.Attributes.ExportTo {
  1389→					if exportTo == visibility.Private || string(exportTo) == ns {
  1390→						// exportTo with same namespace is effectively private
  1391→						ps.ServiceIndex.privateByNamespace[ns] = append(ps.ServiceIndex.privateByNamespace[ns], s)
  1392→					} else {
  1393→						// exportTo is a specific target namespace
  1394→						ps.ServiceIndex.exportedToNamespace[string(exportTo)] = append(ps.ServiceIndex.exportedToNamespace[string(exportTo)], s)
  1395→					}
  1396→				}
  1397→			}
  1398→		}
  1399→	}
  1400→
  1401→	ps.initServiceAccounts(env, allServices)
  1402→
  1403→	return nil
  1404→}
