  1406→// SortServicesByCreationTime sorts the list of services in ascending order by their creation time (if available).
  1407→func SortServicesByCreationTime(services []*Service) []*Service {
  1408→	sort.SliceStable(services, func(i, j int) bool {
  1409→		// If creation time is the same, then behavior is nondeterministic. In this case, we can
  1410→		// pick an arbitrary but consistent ordering based on name and namespace, which is unique.
  1411→		// CreationTimestamp is stored in seconds, so this is not uncommon.
  1412→		if services[i].CreationTime.Equal(services[j].CreationTime) {
  1413→			in := services[i].Attributes.Name + "." + services[i].Attributes.Namespace
  1414→			jn := services[j].Attributes.Name + "." + services[j].Attributes.Namespace
  1415→			return in < jn
  1416→		}
  1417→		return services[i].CreationTime.Before(services[j].CreationTime)
  1418→	})
  1419→	return services
  1420→}
