  1900→// EnvoyFilters return the merged EnvoyFilterWrapper of a proxy
  1901→func (ps *PushContext) EnvoyFilters(proxy *Proxy) *EnvoyFilterWrapper {
  1902→	// this should never happen
  1903→	if proxy == nil {
  1904→		return nil
  1905→	}
  1906→	var matchedEnvoyFilters []*EnvoyFilterWrapper
  1907→	// EnvoyFilters supports inheritance (global ones plus namespace local ones).
  1908→	// First get all the filter configs from the config root namespace
  1909→	// and then add the ones from proxy's own namespace
  1910→	if ps.Mesh.RootNamespace != "" {
  1911→		matchedEnvoyFilters = ps.getMatchedEnvoyFilters(proxy, ps.Mesh.RootNamespace)
  1912→	}
  1913→
  1914→	// To prevent duplicate envoyfilters in case root namespace equals proxy's namespace
  1915→	if proxy.ConfigNamespace != ps.Mesh.RootNamespace {
  1916→		matched := ps.getMatchedEnvoyFilters(proxy, proxy.ConfigNamespace)
  1917→		matchedEnvoyFilters = append(matchedEnvoyFilters, matched...)
  1918→	}
  1919→
  1920→	var out *EnvoyFilterWrapper
  1921→	if len(matchedEnvoyFilters) > 0 {
  1922→		out = &EnvoyFilterWrapper{
  1923→			// no need populate workloadSelector, as it is not used later.
  1924→			Patches: make(map[networking.EnvoyFilter_ApplyTo][]*EnvoyFilterConfigPatchWrapper),
  1925→		}
  1926→		// merge EnvoyFilterWrapper
  1927→		for _, efw := range matchedEnvoyFilters {
  1928→			for applyTo, cps := range efw.Patches {
  1929→				for _, cp := range cps {
  1930→					if proxyMatch(proxy, cp) {
  1931→						out.Patches[applyTo] = append(out.Patches[applyTo], cp)
  1932→					}
  1933→				}
  1934→			}
  1935→		}
  1936→	}
  1937→
  1938→	return out
  1939→}
