  1997→type gatewayWithInstances struct {
  1998→	gateway config.Config
  1999→	// If true, ports that are not present in any instance will be used directly (without targetPort translation)
  2000→	// This supports the legacy behavior of selecting gateways by pod label selector
  2001→	legacyGatewaySelector bool
