  2005→func (ps *PushContext) mergeGateways(proxy *Proxy) *MergedGateway {
  2006→	// this should never happen
  2007→	if proxy == nil {
  2008→		return nil
  2009→	}
  2010→	gatewayInstances := make([]gatewayWithInstances, 0)
  2011→
  2012→	var configs []config.Config
  2013→	if features.ScopeGatewayToNamespace {
  2014→		configs = ps.gatewayIndex.namespace[proxy.ConfigNamespace]
  2015→	} else {
  2016→		configs = ps.gatewayIndex.all
  2017→	}
  2018→
  2019→	for _, cfg := range configs {
  2020→		gw := cfg.Spec.(*networking.Gateway)
  2021→		if gwsvcstr, f := cfg.Annotations[InternalGatewayServiceAnnotation]; f {
  2022→			gwsvcs := strings.Split(gwsvcstr, ",")
  2023→			known := map[host.Name]struct{}{}
  2024→			for _, g := range gwsvcs {
  2025→				known[host.Name(g)] = struct{}{}
  2026→			}
  2027→			matchingInstances := make([]*ServiceInstance, 0, len(proxy.ServiceInstances))
  2028→			for _, si := range proxy.ServiceInstances {
  2029→				if _, f := known[si.Service.Hostname]; f && si.Service.Attributes.Namespace == cfg.Namespace {
  2030→					matchingInstances = append(matchingInstances, si)
  2031→				}
  2032→			}
  2033→			// Only if we have a matching instance should we apply the configuration
  2034→			if len(matchingInstances) > 0 {
  2035→				gatewayInstances = append(gatewayInstances, gatewayWithInstances{cfg, false, matchingInstances})
  2036→			}
  2037→		} else if gw.GetSelector() == nil {
  2038→			// no selector. Applies to all workloads asking for the gateway
  2039→			gatewayInstances = append(gatewayInstances, gatewayWithInstances{cfg, true, proxy.ServiceInstances})
  2040→		} else {
  2041→			gatewaySelector := labels.Instance(gw.GetSelector())
  2042→			var workloadLabels labels.Collection
  2043→			// This should never happen except in tests.
  2044→			if proxy.Metadata != nil && len(proxy.Metadata.Labels) > 0 {
  2045→				workloadLabels = labels.Collection{proxy.Metadata.Labels}
  2046→			}
  2047→			if workloadLabels.IsSupersetOf(gatewaySelector) {
  2048→				gatewayInstances = append(gatewayInstances, gatewayWithInstances{cfg, true, proxy.ServiceInstances})
  2049→			}
  2050→		}
  2051→	}
  2052→
  2053→	if len(gatewayInstances) == 0 {
  2054→		return nil
  2055→	}
  2056→
  2057→	return MergeGateways(gatewayInstances, proxy, ps)
  2058→}
