  2069→// ResolveGatewayInstances attempts to resolve all instances that a gateway will be exposed on.
  2070→// Note: this function considers *all* instances of the service; its possible those instances will not actually be properly functioning
  2071→// gateways, so this is not 100% accurate, but sufficient to expose intent to users.
  2072→// The actual configuration generation is done on a per-workload basis and will get the exact set of matched instances for that workload.
  2073→// Three sets are exposed:
  2074→// * Internal addresses (ie istio-ingressgateway.istio-system.svc.cluster.local:80).
  2075→// * External addresses (ie 1.2.3.4), this comes from LoadBalancer services. There may be multiple in some cases (especially multi cluster).
  2076→// * Warnings for references that could not be resolved. These are intended to be user facing.
  2077→func (gc GatewayContext) ResolveGatewayInstances(namespace string, gwsvcs []string, servers []*networking.Server) (internal, external, warns []string) {
  2078→	ports := map[int]struct{}{}
  2079→	for _, s := range servers {
  2080→		ports[int(s.Port.Number)] = struct{}{}
  2081→	}
  2082→	foundInternal := sets.New()
  2083→	foundExternal := sets.New()
  2084→	warnings := []string{}
  2085→	for _, g := range gwsvcs {
  2086→		svc, f := gc.ps.ServiceIndex.HostnameAndNamespace[host.Name(g)][namespace]
  2087→		if !f {
  2088→			otherNamespaces := []string{}
  2089→			for ns := range gc.ps.ServiceIndex.HostnameAndNamespace[host.Name(g)] {
  2090→				otherNamespaces = append(otherNamespaces, `"`+ns+`"`) // Wrap in quotes for output
  2091→			}
  2092→			if len(otherNamespaces) > 0 {
  2093→				sort.Strings(otherNamespaces)
  2094→				warnings = append(warnings, fmt.Sprintf("hostname %q not found in namespace %q, but it was found in namespace(s) %v",
  2095→					g, namespace, strings.Join(otherNamespaces, ", ")))
  2096→			} else {
  2097→				warnings = append(warnings, fmt.Sprintf("hostname %q not found", g))
  2098→			}
  2099→			continue
  2100→		}
  2101→		svcKey := svc.Key()
  2102→		for port := range ports {
  2103→			instances := gc.ps.ServiceIndex.instancesByPort[svcKey][port]
  2104→			if len(instances) > 0 {
  2105→				foundInternal.Insert(fmt.Sprintf("%s:%d", g, port))
  2106→				// Fetch external IPs from all clusters
  2107→				svc.Attributes.ClusterExternalAddresses.ForEach(func(c cluster.ID, externalIPs []string) {
  2108→					foundExternal.Insert(externalIPs...)
  2109→				})
  2110→			} else {
  2111→				if instancesEmpty(gc.ps.ServiceIndex.instancesByPort[svcKey]) {
  2112→					warnings = append(warnings, fmt.Sprintf("no instances found for hostname %q", g))
  2113→				} else {
  2114→					hintPort := sets.New()
  2115→					for _, instances := range gc.ps.ServiceIndex.instancesByPort[svcKey] {
  2116→						for _, i := range instances {
  2117→							if i.Endpoint.EndpointPort == uint32(port) {
  2118→								hintPort.Insert(strconv.Itoa(i.ServicePort.Port))
  2119→							}
  2120→						}
  2121→					}
  2122→					if len(hintPort) > 0 {
  2123→						warnings = append(warnings, fmt.Sprintf(
  2124→							"port %d not found for hostname %q (hint: the service port should be specified, not the workload port. Did you mean one of these ports: %v?)",
  2125→							port, g, hintPort.SortedList()))
  2126→					} else {
  2127→						warnings = append(warnings, fmt.Sprintf("port %d not found for hostname %q", port, g))
  2128→					}
  2129→				}
  2130→			}
  2131→		}
  2132→	}
  2133→	sort.Strings(warnings)
  2134→	return foundInternal.SortedList(), foundExternal.SortedList(), warnings
  2135→}
