  1796→// pre computes WasmPlugins per namespace
  1797→func (ps *PushContext) initWasmPlugins(env *Environment) error {
  1798→	wasmplugins, err := env.List(gvk.WasmPlugin, NamespaceAll)
  1799→	if err != nil {
  1800→		return err
  1801→	}
  1802→
  1803→	sortConfigByCreationTime(wasmplugins)
  1804→	ps.wasmPluginsByNamespace = map[string][]*WasmPluginWrapper{}
  1805→	for _, plugin := range wasmplugins {
  1806→		if pluginWrapper := convertToWasmPluginWrapper(&plugin); pluginWrapper != nil {
  1807→			ps.wasmPluginsByNamespace[plugin.Namespace] = append(ps.wasmPluginsByNamespace[plugin.Namespace], pluginWrapper)
  1808→		}
  1809→	}
  1810→
  1811→	return nil
  1812→}
