  1814→// WasmPlugins return the WasmPluginWrappers of a proxy
  1815→func (ps *PushContext) WasmPlugins(proxy *Proxy) map[extensions.PluginPhase][]*WasmPluginWrapper {
  1816→	if proxy == nil {
  1817→		return nil
  1818→	}
  1819→	var workloadLabels labels.Collection
  1820→	if proxy.Metadata != nil && len(proxy.Metadata.Labels) > 0 {
  1821→		workloadLabels = labels.Collection{proxy.Metadata.Labels}
  1822→	}
  1823→	matchedPlugins := make(map[extensions.PluginPhase][]*WasmPluginWrapper)
  1824→	// First get all the extension configs from the config root namespace
  1825→	// and then add the ones from proxy's own namespace
  1826→	if ps.Mesh.RootNamespace != "" {
  1827→		// if there is no workload selector, the config applies to all workloads
  1828→		// if there is a workload selector, check for matching workload labels
  1829→		for _, plugin := range ps.wasmPluginsByNamespace[ps.Mesh.RootNamespace] {
  1830→			if plugin.Selector == nil || workloadLabels.IsSupersetOf(plugin.Selector.MatchLabels) {
  1831→				matchedPlugins[plugin.Phase] = append(matchedPlugins[plugin.Phase], plugin)
  1832→			}
  1833→		}
  1834→	}
  1835→
  1836→	// To prevent duplicate extensions in case root namespace equals proxy's namespace
  1837→	if proxy.ConfigNamespace != ps.Mesh.RootNamespace {
  1838→		for _, plugin := range ps.wasmPluginsByNamespace[proxy.ConfigNamespace] {
  1839→			if plugin.Selector == nil || workloadLabels.IsSupersetOf(plugin.Selector.MatchLabels) {
  1840→				matchedPlugins[plugin.Phase] = append(matchedPlugins[plugin.Phase], plugin)
  1841→			}
  1842→		}
  1843→	}
  1844→
  1845→	// sort slices by priority
  1846→	for i, slice := range matchedPlugins {
  1847→		sort.SliceStable(slice, func(i, j int) bool {
  1848→			iPriority := int64(math.MinInt64)
  1849→			if prio := slice[i].Priority; prio != nil {
  1850→				iPriority = prio.Value
  1851→			}
  1852→			jPriority := int64(math.MinInt64)
  1853→			if prio := slice[j].Priority; prio != nil {
  1854→				jPriority = prio.Value
  1855→			}
  1856→			return iPriority > jPriority
  1857→		})
  1858→		matchedPlugins[i] = slice
  1859→	}
  1860→
  1861→	return matchedPlugins
  1862→}
