  1864→// pre computes envoy filters per namespace
  1865→func (ps *PushContext) initEnvoyFilters(env *Environment) error {
  1866→	envoyFilterConfigs, err := env.List(gvk.EnvoyFilter, NamespaceAll)
  1867→	if err != nil {
  1868→		return err
  1869→	}
  1870→
  1871→	sort.Slice(envoyFilterConfigs, func(i, j int) bool {
  1872→		ifilter := envoyFilterConfigs[i].Spec.(*networking.EnvoyFilter)
  1873→		jfilter := envoyFilterConfigs[j].Spec.(*networking.EnvoyFilter)
  1874→		if ifilter.Priority != jfilter.Priority {
  1875→			return ifilter.Priority < jfilter.Priority
  1876→		}
  1877→		// If priority is same fallback to name and creation timestamp, else use priority.
  1878→		// If creation time is the same, then behavior is nondeterministic. In this case, we can
  1879→		// pick an arbitrary but consistent ordering based on name and namespace, which is unique.
  1880→		// CreationTimestamp is stored in seconds, so this is not uncommon.
  1881→		if envoyFilterConfigs[i].CreationTimestamp != envoyFilterConfigs[j].CreationTimestamp {
  1882→			return envoyFilterConfigs[i].CreationTimestamp.Before(envoyFilterConfigs[j].CreationTimestamp)
  1883→		}
  1884→		in := envoyFilterConfigs[i].Name + "." + envoyFilterConfigs[i].Namespace
  1885→		jn := envoyFilterConfigs[j].Name + "." + envoyFilterConfigs[j].Namespace
  1886→		return in < jn
  1887→	})
  1888→
  1889→	ps.envoyFiltersByNamespace = make(map[string][]*EnvoyFilterWrapper)
  1890→	for _, envoyFilterConfig := range envoyFilterConfigs {
  1891→		efw := convertToEnvoyFilterWrapper(&envoyFilterConfig)
  1892→		if _, exists := ps.envoyFiltersByNamespace[envoyFilterConfig.Namespace]; !exists {
  1893→			ps.envoyFiltersByNamespace[envoyFilterConfig.Namespace] = make([]*EnvoyFilterWrapper, 0)
  1894→		}
  1895→		ps.envoyFiltersByNamespace[envoyFilterConfig.Namespace] = append(ps.envoyFiltersByNamespace[envoyFilterConfig.Namespace], efw)
  1896→	}
  1897→	return nil
  1898→}
  1899→
  1900→// EnvoyFilters return the merged EnvoyFilterWrapper of a proxy
  1901→func (ps *PushContext) EnvoyFilters(proxy *Proxy) *EnvoyFilterWrapper {
  1902→	// this should never happen
  1903→	if proxy == nil {
  1904→		return nil
  1905→	}
  1906→	var matchedEnvoyFilters []*EnvoyFilterWrapper
  1907→	// EnvoyFilters supports inheritance (global ones plus namespace local ones).
  1908→	// First get all the filter configs from the config root namespace
  1909→	// and then add the ones from proxy's own namespace
  1910→	if ps.Mesh.RootNamespace != "" {
  1911→		matchedEnvoyFilters = ps.getMatchedEnvoyFilters(proxy, ps.Mesh.RootNamespace)
  1912→	}
  1913→
  1914→	// To prevent duplicate envoyfilters in case root namespace equals proxy's namespace
  1915→	if proxy.ConfigNamespace != ps.Mesh.RootNamespace {
  1916→		matched := ps.getMatchedEnvoyFilters(proxy, proxy.ConfigNamespace)
  1917→		matchedEnvoyFilters = append(matchedEnvoyFilters, matched...)
  1918→	}
  1919→
  1920→	var out *EnvoyFilterWrapper
  1921→	if len(matchedEnvoyFilters) > 0 {
  1922→		out = &EnvoyFilterWrapper{
  1923→			// no need populate workloadSelector, as it is not used later.
  1924→			Patches: make(map[networking.EnvoyFilter_ApplyTo][]*EnvoyFilterConfigPatchWrapper),
  1925→		}
  1926→		// merge EnvoyFilterWrapper
  1927→		for _, efw := range matchedEnvoyFilters {
  1928→			for applyTo, cps := range efw.Patches {
  1929→				for _, cp := range cps {
  1930→					if proxyMatch(proxy, cp) {
  1931→						out.Patches[applyTo] = append(out.Patches[applyTo], cp)
  1932→					}
  1933→				}
  1934→			}
  1935→		}
  1936→	}
  1937→
  1938→	return out
  1939→}
  1940→
  1941→// if there is no workload selector, the config applies to all workloads
  1942→// if there is a workload selector, check for matching workload labels
  1943→func (ps *PushContext) getMatchedEnvoyFilters(proxy *Proxy, namespaces string) []*EnvoyFilterWrapper {
  1944→	matchedEnvoyFilters := make([]*EnvoyFilterWrapper, 0)
  1945→	for _, efw := range ps.envoyFiltersByNamespace[namespaces] {
  1946→		var workloadLabels labels.Collection
  1947→		if proxy.Metadata != nil && len(proxy.Metadata.Labels) > 0 {
  1948→			workloadLabels = labels.Collection{proxy.Metadata.Labels}
  1949→		}
  1950→		if efw.workloadSelector == nil || workloadLabels.IsSupersetOf(efw.workloadSelector) {
  1951→			matchedEnvoyFilters = append(matchedEnvoyFilters, efw)
  1952→		}
  1953→	}
  1954→	return matchedEnvoyFilters
  1955→}
