  1864→// pre computes envoy filters per namespace
  1865→func (ps *PushContext) initEnvoyFilters(env *Environment) error {
  1866→	envoyFilterConfigs, err := env.List(gvk.EnvoyFilter, NamespaceAll)
  1867→	if err != nil {
  1868→		return err
  1869→	}
  1870→
  1871→	sort.Slice(envoyFilterConfigs, func(i, j int) bool {
  1872→		ifilter := envoyFilterConfigs[i].Spec.(*networking.EnvoyFilter)
  1873→		jfilter := envoyFilterConfigs[j].Spec.(*networking.EnvoyFilter)
  1874→		if ifilter.Priority != jfilter.Priority {
  1875→			return ifilter.Priority < jfilter.Priority
  1876→		}
  1877→		// If priority is same fallback to name and creation timestamp, else use priority.
  1878→		// If creation time is the same, then behavior is nondeterministic. In this case, we can
  1879→		// pick an arbitrary but consistent ordering based on name and namespace, which is unique.
  1880→		// CreationTimestamp is stored in seconds, so this is not uncommon.
  1881→		if envoyFilterConfigs[i].CreationTimestamp != envoyFilterConfigs[j].CreationTimestamp {
  1882→			return envoyFilterConfigs[i].CreationTimestamp.Before(envoyFilterConfigs[j].CreationTimestamp)
  1883→		}
  1884→		in := envoyFilterConfigs[i].Name + "." + envoyFilterConfigs[i].Namespace
  1885→		jn := envoyFilterConfigs[j].Name + "." + envoyFilterConfigs[j].Namespace
  1886→		return in < jn
  1887→	})
  1888→
  1889→	ps.envoyFiltersByNamespace = make(map[string][]*EnvoyFilterWrapper)
  1890→	for _, envoyFilterConfig := range envoyFilterConfigs {
  1891→		efw := convertToEnvoyFilterWrapper(&envoyFilterConfig)
  1892→		if _, exists := ps.envoyFiltersByNamespace[envoyFilterConfig.Namespace]; !exists {
  1893→			ps.envoyFiltersByNamespace[envoyFilterConfig.Namespace] = make([]*EnvoyFilterWrapper, 0)
  1894→		}
  1895→		ps.envoyFiltersByNamespace[envoyFilterConfig.Namespace] = append(ps.envoyFiltersByNamespace[envoyFilterConfig.Namespace], efw)
  1896→	}
  1897→	return nil
  1898→}
