  1977→		ps.gatewayIndex.namespace = make(map[string][]config.Config)
  1978→		for _, gatewayConfig := range gatewayConfigs {
  1979→			if _, exists := ps.gatewayIndex.namespace[gatewayConfig.Namespace]; !exists {
  1980→				ps.gatewayIndex.namespace[gatewayConfig.Namespace] = make([]config.Config, 0)
  1981→			}
  1982→			ps.gatewayIndex.namespace[gatewayConfig.Namespace] = append(ps.gatewayIndex.namespace[gatewayConfig.Namespace], gatewayConfig)
  1983→		}
  1984→	} else {
  1985→		ps.gatewayIndex.all = gatewayConfigs
  1986→	}
  1987→	return nil
  1988→}
  1989→
  1990→// InternalGatewayServiceAnnotation represents the hostname of the service a gateway will use. This is
  1991→// only used internally to transfer information from the Kubernetes Gateway API to the Istio Gateway API
  1992→// which does not have a field to represent this.
  1993→// The format is a comma separated list of hostnames. For example, "ingress.istio-system.svc.cluster.local,ingress.example.com"
  1994→// The Gateway will apply to all ServiceInstances of these services, *in the same namespace as the Gateway*.
  1995→const InternalGatewayServiceAnnotation = "internal.istio.io/gateway-service"
  1996→
  1997→type gatewayWithInstances struct {
  1998→	gateway config.Config
  1999→	// If true, ports that are not present in any instance will be used directly (without targetPort translation)
  2000→	// This supports the legacy behavior of selecting gateways by pod label selector
  2001→	legacyGatewaySelector bool
  2002→	instances             []*ServiceInstance
  2003→}
  2004→
  2005→func (ps *PushContext) mergeGateways(proxy *Proxy) *MergedGateway {
  2006→	// this should never happen
  2007→	if proxy == nil {
  2008→		return nil
  2009→	}
  2010→	gatewayInstances := make([]gatewayWithInstances, 0)
  2011→
  2012→	var configs []config.Config
  2013→	if features.ScopeGatewayToNamespace {
  2014→		configs = ps.gatewayIndex.namespace[proxy.ConfigNamespace]
  2015→	} else {
  2016→		configs = ps.gatewayIndex.all
  2017→	}
  2018→
  2019→	for _, cfg := range configs {
  2020→		gw := cfg.Spec.(*networking.Gateway)
  2021→		if gwsvcstr, f := cfg.Annotations[InternalGatewayServiceAnnotation]; f {
  2022→			gwsvcs := strings.Split(gwsvcstr, ",")
  2023→			known := map[host.Name]struct{}{}
  2024→			for _, g := range gwsvcs {
  2025→				known[host.Name(g)] = struct{}{}
  2026→			}
  2027→			matchingInstances := make([]*ServiceInstance, 0, len(proxy.ServiceInstances))
  2028→			for _, si := range proxy.ServiceInstances {
  2029→				if _, f := known[si.Service.Hostname]; f && si.Service.Attributes.Namespace == cfg.Namespace {
  2030→					matchingInstances = append(matchingInstances, si)
  2031→				}
  2032→			}
  2033→			// Only if we have a matching instance should we apply the configuration
  2034→			if len(matchingInstances) > 0 {
  2035→				gatewayInstances = append(gatewayInstances, gatewayWithInstances{cfg, false, matchingInstances})
  2036→			}
  2037→		} else if gw.GetSelector() == nil {
  2038→			// no selector. Applies to all workloads asking for the gateway
  2039→			gatewayInstances = append(gatewayInstances, gatewayWithInstances{cfg, true, proxy.ServiceInstances})
  2040→		} else {
  2041→			gatewaySelector := labels.Instance(gw.GetSelector())
  2042→			var workloadLabels labels.Collection
  2043→			// This should never happen except in tests.
  2044→			if proxy.Metadata != nil && len(proxy.Metadata.Labels) > 0 {
  2045→				workloadLabels = labels.Collection{proxy.Metadata.Labels}
  2046→			}
  2047→			if workloadLabels.IsSupersetOf(gatewaySelector) {
  2048→				gatewayInstances = append(gatewayInstances, gatewayWithInstances{cfg, true, proxy.ServiceInstances})
  2049→			}
  2050→		}
  2051→	}
  2052→
  2053→	if len(gatewayInstances) == 0 {
  2054→		return nil
  2055→	}
  2056→
  2057→	return MergeGateways(gatewayInstances, proxy, ps)
  2058→}
  2059→
  2060→// GatewayContext contains a minimal subset of push context functionality to be exposed to GatewayAPIControllers
  2061→type GatewayContext struct {
  2062→	ps *PushContext
  2063→}
  2064→
  2065→func NewGatewayContext(ps *PushContext) GatewayContext {
  2066→	return GatewayContext{ps}
  2067→}
  2068→
  2069→// ResolveGatewayInstances attempts to resolve all instances that a gateway will be exposed on.
  2070→// Note: this function considers *all* instances of the service; its possible those instances will not actually be properly functioning
  2071→// gateways, so this is not 100% accurate, but sufficient to expose intent to users.
  2072→// The actual configuration generation is done on a per-workload basis and will get the exact set of matched instances for that workload.
  2073→// Three sets are exposed:
  2074→// * Internal addresses (ie istio-ingressgateway.istio-system.svc.cluster.local:80).
  2075→// * External addresses (ie 1.2.3.4), this comes from LoadBalancer services. There may be multiple in some cases (especially multi cluster).
  2076→// * Warnings for references that could not be resolved. These are intended to be user facing.
  2077→func (gc GatewayContext) ResolveGatewayInstances(namespace string, gwsvcs []string, servers []*networking.Server) (internal, external, warns []string) {
  2078→	ports := map[int]struct{}{}
  2079→	for _, s := range servers {
  2080→		ports[int(s.Port.Number)] = struct{}{}
  2081→	}
  2082→	foundInternal := sets.New()
  2083→	foundExternal := sets.New()
  2084→	warnings := []string{}
  2085→	for _, g := range gwsvcs {
  2086→		svc, f := gc.ps.ServiceIndex.HostnameAndNamespace[host.Name(g)][namespace]
  2087→		if !f {
  2088→			otherNamespaces := []string{}
  2089→			for ns := range gc.ps.ServiceIndex.HostnameAndNamespace[host.Name(g)] {
  2090→				otherNamespaces = append(otherNamespaces, `"`+ns+`"`) // Wrap in quotes for output
  2091→			}
  2092→			if len(otherNamespaces) > 0 {
  2093→				sort.Strings(otherNamespaces)
  2094→				warnings = append(warnings, fmt.Sprintf("hostname %q not found in namespace %q, but it was found in namespace(s) %v",
  2095→					g, namespace, strings.Join(otherNamespaces, ", ")))
  2096→			} else {
  2097→				warnings = append(warnings, fmt.Sprintf("hostname %q not found", g))
  2098→			}
  2099→			continue
  2100→		}
  2101→		svcKey := svc.Key()
  2102→		for port := range ports {
  2103→			instances := gc.ps.ServiceIndex.instancesByPort[svcKey][port]
  2104→			if len(instances) > 0 {
  2105→				foundInternal.Insert(fmt.Sprintf("%s:%d", g, port))
  2106→				// Fetch external IPs from all clusters
  2107→				svc.Attributes.ClusterExternalAddresses.ForEach(func(c cluster.ID, externalIPs []string) {
  2108→					foundExternal.Insert(externalIPs...)
  2109→				})
  2110→			} else {
  2111→				if instancesEmpty(gc.ps.ServiceIndex.instancesByPort[svcKey]) {
  2112→					warnings = append(warnings, fmt.Sprintf("no instances found for hostname %q", g))
  2113→				} else {
  2114→					hintPort := sets.New()
  2115→					for _, instances := range gc.ps.ServiceIndex.instancesByPort[svcKey] {
  2116→						for _, i := range instances {
  2117→							if i.Endpoint.EndpointPort == uint32(port) {
  2118→								hintPort.Insert(strconv.Itoa(i.ServicePort.Port))
  2119→							}
  2120→						}
  2121→					}
  2122→					if len(hintPort) > 0 {
  2123→						warnings = append(warnings, fmt.Sprintf(
  2124→							"port %d not found for hostname %q (hint: the service port should be specified, not the workload port. Did you mean one of these ports: %v?)",
  2125→							port, g, hintPort.SortedList()))
  2126→					} else {
  2127→						warnings = append(warnings, fmt.Sprintf("port %d not found for hostname %q", port, g))
  2128→					}
  2129→				}
  2130→			}
  2131→		}
  2132→	}
  2133→	sort.Strings(warnings)
  2134→	return foundInternal.SortedList(), foundExternal.SortedList(), warnings
  2135→}
  2136→
  2137→func instancesEmpty(m map[int][]*ServiceInstance) bool {
  2138→	for _, instances := range m {
  2139→		if len(instances) > 0 {
  2140→			return false
  2141→		}
  2142→	}
  2143→	return true
  2144→}
  2145→
  2146→func (ps *PushContext) NetworkManager() *NetworkManager {
  2147→	return ps.networkMgr
  2148→}
  2149→

